import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
  RadialLinearScale,
  Filler
} from 'chart.js';
import { Bar, Line, Doughnut, Radar } from 'react-chartjs-2';
import './App.css';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  RadialLinearScale,
  Filler,
  Title,
  Tooltip,
  Legend
);

const API_BASE = 'http://localhost:5000/api';

function App() {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [analysisMode, setAnalysisMode] = useState('individual');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  const [customerData, setCustomerData] = useState({
    Tenure: 12.0,
    OrderCount: 8.0,
    CashbackAmount: 15000.0,
    DaySinceLastOrder: 7.0,
    HourSpendOnApp: 25.0,
    OrderAmountHikeFromlastYear: 12.0,
    CouponUsed: 3,
    NumberOfDeviceRegistered: 2,
    Complain: 0,
    SatisfactionScore: 4,
    WarehouseToHome: 15.0,
    NumberOfAddress: 3,
    CityTier: 2,
    PreferredLoginDevice: 'Mobile Phone',
    PreferredPaymentMode: 'Credit Card',
    PreferedOrderCat: 'Laptop & Accessory',
    Gender: 'Male',
    MaritalStatus: 'Married'
  });

  const [batchFile, setBatchFile] = useState(null);

  // Mouse move effect for dynamic background
  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth) * 100,
        y: (e.clientY / window.innerHeight) * 100
      });
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  const handleInputChange = (field, value) => {
    setCustomerData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleIndividualAnalysis = async () => {
    setLoading(true);
    try {
      const response = await axios.post(`${API_BASE}/analyze-single`, {
        customer_data: customerData
      });
      setResults(response.data);
      setActiveTab('results');
    } catch (error) {
      console.error('Analysis error:', error);
      alert('Error analyzing customer data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  const handleBatchAnalysis = async () => {
    if (!batchFile) {
      alert('Please select a file');
      return;
    }

    setLoading(true);
    const formData = new FormData();
    formData.append('file', batchFile);

    try {
      const response = await axios.post(`${API_BASE}/analyze-batch`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      setBatchResults(response.data);
      setActiveTab('batch-results');
    } catch (error) {
      console.error('Batch analysis error:', error);
      alert('Error analyzing batch data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  return (
    <div className="app">
      {/* Animated Background */}
      <div 
        className="animated-bg"
        style={{
          '--mouse-x': `${mousePosition.x}%`,
          '--mouse-y': `${mousePosition.y}%`
        }}
      >
        <div className="bg-glow-1"></div>
        <div className="bg-glow-2"></div>
        <div className="bg-glow-3"></div>
      </div>

      {/* Floating Particles */}
      <div className="floating-particles">
        {[...Array(15)].map((_, i) => (
          <div key={i} className="particle" style={{
            '--i': i,
            '--size': Math.random() * 4 + 2,
            '--duration': Math.random() * 20 + 10,
            '--delay': Math.random() * 5
          }}></div>
        ))}
      </div>

      {/* Sidebar */}
      <div className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
        <div className="sidebar-header">
          <div className="logo">
            <div className="logo-icon">
              <div className="logo-glow"></div>
              📊
            </div>
            {sidebarOpen && (
              <div className="logo-text">
                <div className="logo-title">ChurnVision</div>
                <div className="logo-subtitle">AI Analytics</div>
              </div>
            )}
          </div>
          <button 
            className="sidebar-toggle glass"
            onClick={() => setSidebarOpen(!sidebarOpen)}
          >
            {sidebarOpen ? '‹' : '›'}
          </button>
        </div>

        <nav className="sidebar-nav">
          <div className="nav-section">
            <div className="nav-label">NAVIGATION</div>
            <button 
              className={`nav-item glass ${activeTab === 'dashboard' ? 'active' : ''}`}
              onClick={() => setActiveTab('dashboard')}
            >
              <span className="nav-icon">🌐</span>
              {sidebarOpen && <span className="nav-text">Dashboard</span>}
              {activeTab === 'dashboard' && <div className="nav-glow"></div>}
            </button>
            <button 
              className={`nav-item glass ${activeTab === 'analyze' ? 'active' : ''}`}
              onClick={() => setActiveTab('analyze')}
            >
              <span className="nav-icon">🔮</span>
              {sidebarOpen && <span className="nav-text">Analyze</span>}
              {activeTab === 'analyze' && <div className="nav-glow"></div>}
            </button>
            <button 
              className={`nav-item glass ${activeTab === 'results' ? 'active' : ''}`}
              onClick={() => setActiveTab('results')}
              disabled={!results}
            >
              <span className="nav-icon">📈</span>
              {sidebarOpen && <span className="nav-text">Insights</span>}
              {activeTab === 'results' && <div className="nav-glow"></div>}
            </button>
          </div>

          <div className="nav-section">
            <div className="nav-label">TOOLS</div>
            <button 
              className={`nav-item glass ${activeTab === 'batch-results' ? 'active' : ''}`}
              onClick={() => setActiveTab('batch-results')}
              disabled={!batchResults}
            >
              <span className="nav-icon">🚀</span>
              {sidebarOpen && <span className="nav-text">Batch AI</span>}
              {activeTab === 'batch-results' && <div className="nav-glow"></div>}
            </button>
            <button 
              className={`nav-item glass ${activeTab === 'reports' ? 'active' : ''}`}
              onClick={() => setActiveTab('reports')}
            >
              <span className="nav-icon">✨</span>
              {sidebarOpen && <span className="nav-text">Magic Reports</span>}
              {activeTab === 'reports' && <div className="nav-glow"></div>}
            </button>
          </div>
        </nav>

        {sidebarOpen && (
          <div className="sidebar-footer glass">
            <div className="user-profile">
              <div className="user-avatar">
                <div className="avatar-glow"></div>
                AI
              </div>
              <div className="user-info">
                <div className="user-name">AI Analyst</div>
                <div className="user-status">Online</div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Main Content */}
      <div className="main-content">
        <header className="header glass">
          <div className="header-left">
            <h1 className="header-title gradient-text">
              {activeTab === 'dashboard' && 'Quantum Dashboard'}
              {activeTab === 'analyze' && 'Neural Analysis'}
              {activeTab === 'results' && 'Crystal Insights'}
              {activeTab === 'batch-results' && 'Batch Intelligence'}
              {activeTab === 'reports' && 'Magic Reports'}
            </h1>
            <p className="header-subtitle">
              {activeTab === 'dashboard' && 'Real-time AI-powered churn intelligence'}
              {activeTab === 'analyze' && 'Deep learning customer analysis'}
              {activeTab === 'results' && 'Crystal clear risk insights'}
              {activeTab === 'batch-results' && 'Bulk customer intelligence'}
              {activeTab === 'reports' && 'Automated smart reporting'}
            </p>
          </div>
          <div className="header-right">
            <div className="header-actions">
              <button className="header-btn glass">
                <span className="btn-icon">⚡</span>
              </button>
              <button className="header-btn glass">
                <span className="btn-icon">🌙</span>
              </button>
              <div className="notification-badge glass">
                <span className="notification-count">3</span>
                <span className="notification-icon">🔔</span>
              </div>
            </div>
          </div>
        </header>

        <div className="content">
          {activeTab === 'dashboard' && (
            <DashboardView 
              onAnalyzeClick={() => setActiveTab('analyze')}
            />
          )}

          {activeTab === 'analyze' && (
            <AnalyzeView 
              customerData={customerData}
              onInputChange={handleInputChange}
              onAnalyze={handleIndividualAnalysis}
              loading={loading}
              analysisMode={analysisMode}
              setAnalysisMode={setAnalysisMode}
              onFileChange={(e) => setBatchFile(e.target.files[0])}
              onBatchAnalyze={handleBatchAnalysis}
            />
          )}

          {activeTab === 'results' && results && (
            <ResultsView 
              results={results}
              customerData={customerData}
            />
          )}

          {activeTab === 'batch-results' && batchResults && (
            <BatchResultsView 
              results={batchResults}
            />
          )}

          {activeTab === 'reports' && (
            <ReportsView 
              results={results}
              batchResults={batchResults}
            />
          )}
        </div>
      </div>
    </div>
  );
}

// Dashboard Component
const DashboardView = ({ onAnalyzeClick }) => {
  const [stats, setStats] = useState({
    totalCustomers: 12547,
    churnRate: 12.3,
    atRisk: 1842,
    retentionRate: 87.7
  });

  const quickActions = [
    { icon: '🔮', title: 'Smart Analysis', description: 'AI-powered individual analysis', color: 'var(--purple)', action: onAnalyzeClick },
    { icon: '🚀', title: 'Batch Process', description: 'Upload & analyze multiple customers', color: 'var(--cyan)', action: onAnalyzeClick },
    { icon: '📊', title: 'Live Reports', description: 'Real-time analytics dashboard', color: 'var(--pink)', action: () => {} },
    { icon: '🤖', title: 'AI Assistant', description: 'Get intelligent recommendations', color: 'var(--orange)', action: () => {} }
  ];

  return (
    <div className="dashboard">
      {/* Welcome Card */}
      <div className="welcome-card glass">
        <div className="welcome-content">
          <h1>Welcome to ChurnVision AI</h1>
          <p>Advanced machine learning platform for customer churn prediction and prevention</p>
          <div className="welcome-stats">
            <div className="welcome-stat">
              <div className="stat-value">99.7%</div>
              <div className="stat-label">Accuracy</div>
            </div>
            <div className="welcome-stat">
              <div className="stat-value">24/7</div>
              <div className="stat-label">Monitoring</div>
            </div>
            <div className="welcome-stat">
              <div className="stat-value">AI</div>
              <div className="stat-label">Powered</div>
            </div>
          </div>
        </div>
        <div className="welcome-graphic">
          <div className="floating-orb"></div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="quick-actions-grid">
        {quickActions.map((action, index) => (
          <div 
            key={index} 
            className="action-card glass hover-lift"
            onClick={action.action}
            style={{ '--accent': action.color }}
          >
            <div className="action-icon" style={{ background: action.color }}>
              {action.icon}
            </div>
            <div className="action-content">
              <h3>{action.title}</h3>
              <p>{action.description}</p>
            </div>
            <div className="action-arrow">→</div>
          </div>
        ))}
      </div>

      {/* Stats Overview */}
      <div className="stats-grid">
        <div className="stat-card glass" style={{ '--accent': 'var(--green)' }}>
          <div className="stat-glow"></div>
          <div className="stat-content">
            <div className="stat-value">{stats.totalCustomers.toLocaleString()}</div>
            <div className="stat-label">Total Customers</div>
            <div className="stat-trend positive">+2.4%</div>
          </div>
          <div className="stat-icon">👥</div>
        </div>

        <div className="stat-card glass" style={{ '--accent': 'var(--red)' }}>
          <div className="stat-glow"></div>
          <div className="stat-content">
            <div className="stat-value">{stats.churnRate}%</div>
            <div className="stat-label">Churn Rate</div>
            <div className="stat-trend negative">+0.8%</div>
          </div>
          <div className="stat-icon">📉</div>
        </div>

        <div className="stat-card glass" style={{ '--accent': 'var(--orange)' }}>
          <div className="stat-glow"></div>
          <div className="stat-content">
            <div className="stat-value">{stats.atRisk.toLocaleString()}</div>
            <div className="stat-label">At Risk</div>
            <div className="stat-trend negative">+124</div>
          </div>
          <div className="stat-icon">⚠️</div>
        </div>

        <div className="stat-card glass" style={{ '--accent': 'var(--cyan)' }}>
          <div className="stat-glow"></div>
          <div className="stat-content">
            <div className="stat-value">{stats.retentionRate}%</div>
            <div className="stat-label">Retention Rate</div>
            <div className="stat-trend positive">+1.2%</div>
          </div>
          <div className="stat-icon">💎</div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="charts-section">
        <div className="chart-container glass">
          <h3>Risk Distribution</h3>
          <RiskDistributionChart />
        </div>
        <div className="chart-container glass">
          <h3>Trend Analysis</h3>
          <TrendChart />
        </div>
      </div>
    </div>
  );
};

// Chart Components
const RiskDistributionChart = () => {
  const data = {
    labels: ['Low Risk', 'Medium Risk', 'High Risk', 'Critical'],
    datasets: [
      {
        data: [45, 30, 20, 5],
        backgroundColor: [
          'rgba(16, 185, 129, 0.8)',
          'rgba(245, 158, 11, 0.8)',
          'rgba(249, 115, 22, 0.8)',
          'rgba(239, 68, 68, 0.8)'
        ],
        borderColor: [
          'rgb(16, 185, 129)',
          'rgb(245, 158, 11)',
          'rgb(249, 115, 22)',
          'rgb(239, 68, 68)'
        ],
        borderWidth: 2,
        borderRadius: 8,
      },
    ],
  };

  const options = {
    plugins: {
      legend: {
        position: 'bottom',
        labels: {
          color: 'rgba(255, 255, 255, 0.8)',
          font: {
            size: 12
          },
          padding: 20
        }
      },
    },
    cutout: '60%',
  };

  return (
    <div className="chart-wrapper">
      <Doughnut data={data} options={options} />
    </div>
  );
};

const TrendChart = () => {
  const data = {
    labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    datasets: [
      {
        label: 'Churn Rate',
        data: [15, 14, 16, 13, 12.5, 12.3],
        borderColor: 'rgb(239, 68, 68)',
        backgroundColor: 'rgba(239, 68, 68, 0.1)',
        borderWidth: 3,
        fill: true,
        tension: 0.4,
      },
      {
        label: 'Retention Rate',
        data: [82, 83, 81, 84, 85, 87.7],
        borderColor: 'rgb(16, 185, 129)',
        backgroundColor: 'rgba(16, 185, 129, 0.1)',
        borderWidth: 3,
        fill: true,
        tension: 0.4,
      },
    ],
  };

  const options = {
    plugins: {
      legend: {
        labels: {
          color: 'rgba(255, 255, 255, 0.8)',
        }
      },
    },
    scales: {
      y: {
        grid: {
          color: 'rgba(255, 255, 255, 0.1)',
        },
        ticks: {
          color: 'rgba(255, 255, 255, 0.6)',
        },
      },
      x: {
        grid: {
          color: 'rgba(255, 255, 255, 0.1)',
        },
        ticks: {
          color: 'rgba(255, 255, 255, 0.6)',
        },
      },
    },
  };

  return (
    <div className="chart-wrapper">
      <Line data={data} options={options} />
    </div>
  );
};

// Analyze View Component
const AnalyzeView = ({ 
  customerData, 
  onInputChange, 
  onAnalyze, 
  loading, 
  analysisMode, 
  setAnalysisMode,
  onFileChange,
  onBatchAnalyze 
}) => {
  const [activeSection, setActiveSection] = useState('basic');

  const renderInputField = (label, field, type = 'number', options = null) => {
    if (type === 'select') {
      return (
        <div className="form-group">
          <label className="form-label">{label}</label>
          <select 
            className="form-select glass"
            value={customerData[field]} 
            onChange={(e) => onInputChange(field, e.target.value)}
          >
            {options.map(option => (
              <option key={option} value={option}>{option}</option>
            ))}
          </select>
        </div>
      );
    }

    if (type === 'toggle') {
      return (
        <div className="form-group">
          <label className="form-label">{label}</label>
          <div className="toggle-group">
            <button 
              type="button"
              className={`toggle-btn glass ${customerData[field] ? 'active' : ''}`}
              onClick={() => onInputChange(field, 1)}
            >
              Yes
            </button>
            <button 
              type="button"
              className={`toggle-btn glass ${!customerData[field] ? 'active' : ''}`}
              onClick={() => onInputChange(field, 0)}
            >
              No
            </button>
          </div>
        </div>
      );
    }

    return (
      <div className="form-group">
        <label className="form-label">{label}</label>
        <input 
          className="form-input glass"
          type={type}
          value={customerData[field]}
          onChange={(e) => onInputChange(field, parseFloat(e.target.value) || e.target.value)}
          step={type === 'number' ? 'any' : undefined}
        />
      </div>
    );
  };

  return (
    <div className="analyze-view">
      {/* Mode Selection */}
      <div className="mode-selection">
        <div className="mode-tabs glass">
          <button 
            className={`mode-tab ${analysisMode === 'individual' ? 'active' : ''}`}
            onClick={() => setAnalysisMode('individual')}
          >
            <span className="tab-icon">🔮</span>
            AI Analysis
          </button>
          <button 
            className={`mode-tab ${analysisMode === 'batch' ? 'active' : ''}`}
            onClick={() => setAnalysisMode('batch')}
          >
            <span className="tab-icon">🚀</span>
            Batch AI
          </button>
        </div>
      </div>

      {analysisMode === 'individual' ? (
        <div className="analysis-content">
          <div className="analysis-header">
            <h1 className="gradient-text">Neural Customer Analysis</h1>
            <p>Enter customer details for AI-powered churn risk prediction</p>
          </div>

          <div className="analysis-card glass">
            {/* Navigation Tabs */}
            <div className="section-tabs glass">
              <button 
                className={`section-tab ${activeSection === 'basic' ? 'active' : ''}`}
                onClick={() => setActiveSection('basic')}
              >
                📊 Core Metrics
              </button>
              <button 
                className={`section-tab ${activeSection === 'behavioral' ? 'active' : ''}`}
                onClick={() => setActiveSection('behavioral')}
              >
                🎯 Behavior
              </button>
              <button 
                className={`section-tab ${activeSection === 'demographic' ? 'active' : ''}`}
                onClick={() => setActiveSection('demographic')}
              >
                👤 Profile
              </button>
            </div>

            {/* Form Sections */}
            <div className="form-sections">
              {activeSection === 'basic' && (
                <div className="form-section">
                  <div className="form-columns">
                    <div className="form-column">
                      {renderInputField("🕒 Customer Tenure (Months)", "Tenure")}
                      {renderInputField("📦 Total Orders", "OrderCount")}
                      {renderInputField("💰 Cashback Amount (₹)", "CashbackAmount")}
                      {renderInputField("📅 Days Since Last Order", "DaySinceLastOrder")}
                    </div>
                    <div className="form-column">
                      {renderInputField("⭐ Satisfaction Score (1-5)", "SatisfactionScore", "number")}
                      {renderInputField("🏢 Warehouse Distance (km)", "WarehouseToHome")}
                      {renderInputField("🏙️ City Tier", "CityTier", "number")}
                      {renderInputField("📢 Formal Complaint", "Complain", "toggle")}
                    </div>
                  </div>
                </div>
              )}

              {activeSection === 'behavioral' && (
                <div className="form-section">
                  <div className="form-columns">
                    <div className="form-column">
                      {renderInputField("📱 App Usage (Hours/month)", "HourSpendOnApp")}
                      {renderInputField("📈 Price Hike Perception (%)", "OrderAmountHikeFromlastYear")}
                      {renderInputField("🎫 Coupons Used", "CouponUsed")}
                      {renderInputField("📱 Devices Registered", "NumberOfDeviceRegistered")}
                    </div>
                    <div className="form-column">
                      {renderInputField("🏠 Delivery Addresses", "NumberOfAddress")}
                      {renderInputField("💻 Login Device", "PreferredLoginDevice", "select", ['Mobile Phone', 'Computer'])}
                      {renderInputField("💳 Payment Method", "PreferredPaymentMode", "select", ['Credit Card', 'Debit Card', 'UPI', 'E wallet', 'Cash on Delivery'])}
                      {renderInputField("🛍️ Preferred Category", "PreferedOrderCat", "select", ['Laptop & Accessory', 'Mobile Phone', 'Fashion', 'Grocery', 'Others'])}
                    </div>
                  </div>
                </div>
              )}

              {activeSection === 'demographic' && (
                <div className="form-section">
                  <div className="form-columns">
                    <div className="form-column">
                      {renderInputField("👤 Gender", "Gender", "select", ['Male', 'Female', 'Other'])}
                    </div>
                    <div className="form-column">
                      {renderInputField("💍 Marital Status", "MaritalStatus", "select", ['Single', 'Married', 'Divorced', 'Other'])}
                    </div>
                  </div>
                </div>
              )}
            </div>

            {/* Action Button */}
            <div className="analysis-actions">
              <button 
                className="analyze-btn magic"
                onClick={onAnalyze}
                disabled={loading}
              >
                {loading ? (
                  <>
                    <div className="loading-spinner"></div>
                    AI is Analyzing...
                  </>
                ) : (
                  <>
                    <span className="btn-glow"></span>
                    <span className="btn-icon">✨</span>
                    Launch AI Analysis
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      ) : (
        <div className="batch-analysis">
          <div className="batch-header">
            <h1 className="gradient-text">Batch AI Processing</h1>
            <p>Upload customer data for bulk AI analysis and insights</p>
          </div>

          <div className="upload-area">
            <div className="upload-card glass magic-hover">
              <div className="upload-icon">🚀</div>
              <h3>AI Batch Processing</h3>
              <p>Upload CSV file for intelligent bulk analysis</p>
              <input 
                type="file" 
                accept=".csv"
                onChange={onFileChange}
                className="file-input"
              />
              <button 
                className="analyze-btn secondary"
                onClick={onBatchAnalyze}
                disabled={loading}
              >
                {loading ? 'AI Processing...' : 'Start Batch AI'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

